<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Arial, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    flex-direction: column;
  }
  h1 {
    font-size: 3rem;
    margin-bottom: 0.25rem;
    letter-spacing: 0.1em;
    color: #f0e68c;
  }
  #score-display {
    font-size: 1.2rem;
    margin-bottom: 1rem;
    background: #16213e;
    padding: 0.4rem 1.5rem;
    border-radius: 8px;
  }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(4, 1fr);
    gap: 10px;
    width: 420px;
    height: 420px;
    background: #16213e;
    border-radius: 12px;
    padding: 10px;
    position: relative;
  }
  .tile {
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 2rem;
    font-weight: bold;
    border-radius: 8px;
    background: #0f3460;
    color: #e0e0e0;
    transition: transform 0.1s ease;
  }
  .tile[data-value="2"]   { background: #2a2a5a; color: #c8d6e5; }
  .tile[data-value="4"]   { background: #3a3a7a; color: #dfe6e9; }
  .tile[data-value="8"]   { background: #e17055; color: #fff; }
  .tile[data-value="16"]  { background: #d63031; color: #fff; }
  .tile[data-value="32"]  { background: #e84393; color: #fff; }
  .tile[data-value="64"]  { background: #fd79a8; color: #fff; }
  .tile[data-value="128"] { background: #f0e68c; color: #1a1a2e; font-size: 1.7rem; }
  .tile[data-value="256"] { background: #ffeaa7; color: #1a1a2e; font-size: 1.7rem; }
  .tile[data-value="512"] { background: #00cec9; color: #1a1a2e; font-size: 1.7rem; }
  .tile[data-value="1024"]{ background: #6c5ce7; color: #fff; font-size: 1.4rem; }
  .tile[data-value="2048"]{ background: #fdcb6e; color: #1a1a2e; font-size: 1.4rem; }
  #reset {
    margin-top: 1.2rem;
    padding: 0.6rem 2rem;
    font-size: 1rem;
    background: #e17055;
    color: #fff;
    border: none;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.2s;
  }
  #reset:hover { background: #d63031; }
</style>
</head>
<body>

<h1>2048</h1>
<div id="score-display">Score: <span id="score">0</span></div>
<div id="board"></div>
<button id="reset">New Game</button>

<script>
(function() {
  const SIZE = 4;
  let board = [];
  let scoreVal = 0;

  function createTile(val) {
    const el = document.createElement('div');
    el.className = 'tile';
    el.setAttribute('data-value', val);
    el.textContent = val || '';
    return el;
  }

  function render() {
    const boardEl = document.getElementById('board');
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const val = board[r][c];
        if (val === 0) {
          const empty = document.createElement('div');
          empty.className = 'tile';
          boardEl.appendChild(empty);
        } else {
          boardEl.appendChild(createTile(val));
        }
      }
    }
    document.getElementById('score').textContent = scoreVal;
  }

  function cloneBoard(b) {
    return b.map(row => [...row]);
  }

  function isEmpty(a, b) {
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (a[r][c] !== b[r][c]) return false;
    return true;
  }

  function rotateBoard(b, times) {
    let result = cloneBoard(b);
    for (let t = 0; t < times; t++) {
      const rotated = Array.from({length: SIZE}, () => Array(SIZE).fill(0));
      for (let r = 0; r < SIZE; r++)
        for (let c = 0; c < SIZE; c++)
          rotated[c][SIZE - 1 - r] = result[r][c];
      result = rotated;
    }
    return result;
  }

  function rotateBack(b, times) {
    return rotateBoard(b, (4 - times % 4) % 4);
  }

  // Slide a single row left: merge and compact
  function slideRow(row) {
    let added = 0;
    // Remove zeros
    let filtered = row.filter(v => v !== 0);
    // Merge from left
    let merged = [];
    let i = 0;
    while (i < filtered.length) {
      if (i + 1 < filtered.length && filtered[i] === filtered[i + 1]) {
        const val = filtered[i] * 2;
        merged.push(val);
        added += val;
        i += 2;
      } else {
        merged.push(filtered[i]);
        i++;
      }
    }
    // Pad with zeros
    while (merged.length < SIZE) merged.push(0);
    return { row: merged, score: added };
  }

  function move(direction) {
    let rotations = 0;
    if (direction === 'right') rotations = 2;
    else if (direction === 'up') rotations = 3; // rotate left once to bring up to left
    else if (direction === 'down') rotations = 1;

    const rotated = rotateBoard(board, rotations);
    let totalAdded = 0;
    for (let r = 0; r < SIZE; r++) {
      const result = slideRow(rotated[r]);
      rotated[r] = result.row;
      totalAdded += result.score;
    }

    if (isEmpty(board, rotated)) return false;

    board = rotateBack(rotated, rotations);
    scoreVal += totalAdded;
    spawnTile();
    render();
    return true;
  }

  function spawnTile() {
    const emptyCells = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (board[r][c] === 0) emptyCells.push({r, c});

    if (emptyCells.length === 0) return;

    const cell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
    board[cell.r][cell.c] = Math.random() < 0.9 ? 2 : 4;
  }

  function resetGame() {
    board = Array.from({length: SIZE}, () => Array(SIZE).fill(0));
    scoreVal = 0;
    // Start with exactly 2 tiles
    spawnTile();
    spawnTile();
    render();
  }

  function setBoard(arr) {
    board = arr.map(row => [...row]);
    render();
  }

  window.game = {
    size: SIZE,
    reset: resetGame,
    move: move,
    board: () => cloneBoard(board),
    setBoard: setBoard,
    score: () => scoreVal
  };

  document.getElementById('reset').addEventListener('click', resetGame);

  document.addEventListener('keydown', function(e) {
    const dirMap = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down'
    };
    if (dirMap[e.key]) {
      e.preventDefault();
      window.game.move(dirMap[e.key]);
    }
  });

  resetGame();
})();
</script>
</body>
</html>
